async function exists(relativePath) {
  try {
    await access(path.resolve(relativePath));
    return true;
  } catch {
    return false;
  }
}

async function readJson(relativePath) {
  return JSON.parse(await readFile(path.resolve(relativePath), "utf8"));
}

function collectClaudeFindings(parsedReview) {
  const findings = parsedReview?.findings;
  if (Array.isArray(findings)) return findings;
  if (!findings || typeof findings !== "object") return [];

  const severityByBucket = new Map([
    ["p0", "P0"],
    ["p1", "P1"],
    ["p2", "P2"],
    ["p3", "P3"],
  ]);

  return Object.entries(findings).flatMap(([bucket, bucketFindings]) => {
    if (!Array.isArray(bucketFindings)) return [];
    const bucketSeverity = severityByBucket.get(bucket.toLowerCase()) ?? bucket;
    return bucketFindings.map((finding) => ({
      ...finding,
      severity: finding?.severity ?? bucketSeverity,
    }));
  });
}

function requireIncludes(array, value, label) {
  if (!Array.isArray(array) || !array.includes(value)) errors.push(`${label} missing ${value}`);
}

function requireText(text, value, label) {
  if (!text.includes(value)) errors.push(`${label} missing ${value}`);
}

function collectGateMap(gates) {
  return new Map((gates ?? []).map((gate) => [gate.id, gate]));
}

function evidenceRootFor(subphaseId) {
  return `docs/goal-closeout/${subphaseId.toLowerCase().replaceAll(".", "-")}`;
}

function closeoutPackRootFor(packId) {
  return `docs/closeout-packs/${packId.toLowerCase()}`;
}

function evidenceFilesForCloseout(closeout, evidenceRoot) {
  if (closeout.closeout_pack_ref) {
    return [
      `${evidenceRoot}/manifest.json`,
      `${evidenceRoot}/command-evidence.json`,
      `${evidenceRoot}/claude-review-result.json`,
      `${evidenceRoot}/adjudication.md`,
      `${evidenceRoot}/construction-inspection.json`,
    ];
  }
  return [
    `${evidenceRoot}/packet.json`,
    `${evidenceRoot}/command-evidence.json`,
    `${evidenceRoot}/claude-review-result.json`,
    `${evidenceRoot}/adjudication.md`,
    `${evidenceRoot}/construction-inspection.json`,
  ];
}

function expandSubphaseTemplate(value, subphaseId) {
  return value.replaceAll("{subphase}", subphaseId.toLowerCase().replaceAll(".", "-"));
}

function findWeightedSubphase(weightedLedger, subphaseId) {
  for (const entry of weightedLedger.entries ?? []) {
    const subphase = (entry.implementation_subphases ?? []).find((item) => item.id === subphaseId);
    if (subphase) return { entry, subphase };
  }
  return null;
}

function getWeightedSubphaseBoundary(weightedLedger, subphaseId) {
  const found = findWeightedSubphase(weightedLedger, subphaseId);
  if (!found) return null;
  const subphases = [...(found.entry.implementation_subphases ?? [])].sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
  const index = subphases.findIndex((subphase) => subphase.id === subphaseId);
  if (index === -1) return null;
  const nextSubphase = subphases[index + 1] ?? null;
  return {
    sourceMicroPhaseId: found.entry.source_micro_phase_id,
    subphaseCount: subphases.length,
    order: found.subphase.order,
    terminal: nextSubphase === null,
    nextSubphaseId: nextSubphase?.id ?? null,
  };
}

function traceKey(ref) {
  return `${ref.requirement_id}:${ref.anchor_role}`;
}

function fieldMap(fields) {
  return new Map((fields ?? []).map((field) => [field.name, field]));
}

function isGenerationOrMutatingCommand(command, explicitExcludedCommands = []) {
  if (!command) return false;
  const normalized = command.trim();
  for (const excluded of explicitExcludedCommands) {
    if (normalized === `npm run ${excluded}` || normalized.includes(` ${excluded}`)) return true;
  }
  return /\bnpm run [^\s]*:generate(?:\b|-all\b|:)/.test(normalized) || /\bnpm run rp:generate-all\b/.test(normalized);
}

for (const file of [
  contractPath,
  "packages/control-plane/README.md",
  "docs/spec-requirement-ledger.json",
  "docs/weighted-implementation-ledger.json",
  "docs/closeout-pack-plan/closeout-pack-plan.json",
  "hermes/project.json",
  "package.json",
]) {
  if (!(await exists(file))) errors.push(`missing ${file}`);
}

const contract = await readJson(contractPath);
const requirementLedger = await readJson("docs/spec-requirement-ledger.json");
const weightedLedger = await readJson("docs/weighted-implementation-ledger.json");
const closeoutPackPlan = await readJson("docs/closeout-pack-plan/closeout-pack-plan.json");
const hermesProject = await readJson("hermes/project.json");
const packageJson = await readJson("package.json");
const readme = await readFile(path.resolve("packages/control-plane/README.md"), "utf8");

if (contract.schema_version !== "law-firm-os.control-plane-contract.v0.1") {
  errors.push("control-plane contract schema mismatch");
}
if (contract.program_id !== "RP00") errors.push("control-plane contract must bind to RP00");
if (contract.hermes_gate !== "H00") errors.push("control-plane contract must bind Hermes H00");
if (contract.claude_gate !== "C00") errors.push("control-plane contract must bind Claude C00");
if (contract.current_subphase?.id !== currentContractSubphaseId) {
  errors.push(`current_subphase must be ${currentContractSubphaseId}`);
}
if (contract.current_subphase?.source_micro_phase_id !== currentSourceMicroPhaseId) {
  errors.push(`source micro phase must be ${currentSourceMicroPhaseId}`);
}
if (contract.current_subphase?.minimum_closeout_status !== "production_ready") {
  errors.push("minimum closeout status must be production_ready");
}
const currentExpectedEvidenceRoot = contract.current_subphase?.closeout_pack_ref
  ? closeoutPackRootFor(contract.current_subphase.closeout_pack_ref)
  : evidenceRootFor(currentContractSubphaseId);
if (contract.current_subphase?.evidence_root !== currentExpectedEvidenceRoot) {
  errors.push(`current evidence root must be ${currentExpectedEvidenceRoot}`);
}

const closeouts = new Map((contract.subphase_closeouts ?? []).map((item) => [item.id, item]));
for (const subphaseId of requiredClosedSubphases) {
  const closeout = closeouts.get(subphaseId);
  if (!closeout) {
    errors.push(`subphase_closeouts missing ${subphaseId}`);
  } else if (closeout.status !== "production_ready") {
    errors.push(`${subphaseId} must remain production_ready`);
  }
}
const currentCloseout = closeouts.get(currentContractSubphaseId);
if (!currentCloseout) {
  errors.push(`subphase_closeouts missing ${currentContractSubphaseId}`);
} else if (currentCloseout.status !== contract.current_subphase?.status) {
  errors.push(`${currentContractSubphaseId} closeout status must match current_subphase status`);
}

for (const source of [
  "contracts/law-firm-os.product-contract.json",
  "docs/spec-requirement-ledger.json",
  "docs/weighted-implementation-ledger.json",
  "docs/rp00-product-constitution-ai-control-plane-detailed-microphases.json",
  "docs/goal-closeout-protocol.md",
  "hermes/project.json",
]) {
  requireIncludes(contract.scope_inventory?.reviewed_sources, source, "scope_inventory.reviewed_sources");
}
for (const source of contract.scope_inventory?.reviewed_sources ?? []) {
  if (!(await exists(source))) errors.push(`reviewed source does not exist: ${source}`);
}

for (const capability of [
  "product_contract",
  "ai_led_development_rules",
  "hermes_attachment",
  "claude_cross_validation",
  "human_approval_gates",
  "blocked_claims",
]) {
  requireIncludes(contract.scope_inventory?.controlled_capabilities, capability, "scope_inventory.controlled_capabilities");
}
for (const workflow of [
  "plan_authoring",
  "ai_implementation_handoff",
  "hermes_validation",
  "claude_review",
  "human_approval",
  "blocked_claim_handling",
]) {
  requireIncludes(contract.scope_inventory?.controlled_workflows, workflow, "scope_inventory.controlled_workflows");
}
for (const nonGoalText of [
  "Hermes does not own or mutate Law Firm OS product code.",
  "Claude Code review does not replace human approval.",
  "Planning artifacts do not count as production implementation by themselves.",
]) {
  requireIncludes(contract.scope_inventory?.explicit_non_goals, nonGoalText, "scope_inventory.explicit_non_goals");
}

const requiredEntityNames = [
  "ProductContract",
  "AIControlRule",
  "HermesGate",
  "ClaudeReviewGate",
  "HumanApproval",
  "BlockedClaim",
];
for (const entity of requiredEntityNames) {
  requireIncludes(contract.scope_inventory?.owned_entities, entity, "scope_inventory.owned_entities");
}

const riskIds = new Set((contract.scope_inventory?.acceptance_risks ?? []).map((risk) => risk.id));
for (const risk of ["scope_drift", "ai_write_without_review", "validation_theater", "harness_product_boundary_confusion"]) {
  if (!riskIds.has(risk)) errors.push(`acceptance_risks missing ${risk}`);
}
for (const risk of contract.scope_inventory?.acceptance_risks ?? []) {
  if (!risk.blocked_claim_rule) errors.push(`acceptance risk ${risk.id} missing blocked_claim_rule`);
  if (risk.id === "ai_write_without_review" && risk.severity !== "P0_BLOCKER") {
    errors.push("ai_write_without_review must be P0_BLOCKER");
  }
}

if (contract.contract_shell?.subphase_id !== contractShellSubphaseId) {
  errors.push(`contract_shell must bind to ${contractShellSubphaseId}`);
}
if (!["implemented", "production_ready"].includes(contract.contract_shell?.status)) {
  errors.push("contract_shell status must be implemented or production_ready");
}
for (const field of ["identifier_policy", "tenant_boundary", "matter_trace", "no_real_data"]) {
  if (!contract.contract_shell?.schema_expectations?.[field]) {
    errors.push(`contract_shell.schema_expectations missing ${field}`);
  }
}

const entityContracts = new Map((contract.contract_shell?.entity_contracts ?? []).map((entity) => [entity.name, entity]));
for (const entityName of requiredEntityNames) {
  const entity = entityContracts.get(entityName);
  if (!entity) {
    errors.push(`entity_contracts missing ${entityName}`);
    continue;
  }
  if (entity.owner_module !== "packages/control-plane") errors.push(`${entityName} owner_module must be packages/control-plane`);
  if (!entity.purpose) errors.push(`${entityName} missing purpose`);
  if (!Array.isArray(entity.required_fields) || entity.required_fields.length < 6) {
    errors.push(`${entityName} must define at least 6 required fields`);
  }
  if (!Array.isArray(entity.status_lifecycle) || entity.status_lifecycle.length < 3) {
    errors.push(`${entityName} must define status lifecycle`);
  }
  if (!entity.sensitive_action_policy) errors.push(`${entityName} missing sensitive_action_policy`);
}

